 1→import { useNavigation } from '@react-navigation/native';
 2→import { NativeStackNavigationProp } from '@react-navigation/native-stack';
 3→import React, { useCallback } from 'react';
 4→import { useWindowDimensions } from 'react-native';
 5→import { eventSelectContent } from '~/constants/functions';
 6→import { useRootStore } from '~/store';
 7→import { PropsRootStack } from '../../../routes/Models';
 8→import {
 9→  ParameterPointsProgramResponse,
10→  ParameterPointsProgramStatus,
11→} from '../../../services/models';
12→import { sanitizeTaxonomy } from '../../../utils/functions';
13→import { LearnMorePointsSectionView } from './view';
14→
15→export default function LearnMorePointsSection() {
16→  const { data, status } = useRootStore(state => state.parameterPointsProgram);
17→  const parameterPointsProgramActions = useRootStore(
18→    state => state.parameterPointsProgramActions,
19→  );
20→  const { width } = useWindowDimensions();
21→  const navigation = useNavigation<NativeStackNavigationProp<PropsRootStack>>();
22→
23→  const handlePress = useCallback(
24→    (category: string) => {
25→      const find = data?.find(
26→        (item: ParameterPointsProgramResponse) =>
27→          item.category.toLowerCase() === category.toLowerCase(),
28→      );
29→
30→      if (!find || !parameterPointsProgramActions) {
31→        return;
32→      }
33→
34→      parameterPointsProgramActions.setSelectedCategory(find);
35→
36→      eventSelectContent({
37→        content_type: 'cta',
38→        content_id: sanitizeTaxonomy(category),
39→        location_1: 'monetizacao',
40→        location_2: 'hub_recompensas_spmais',
41→        location_3: 'saiba_mais',
42→      });
43→
44→      navigation.navigate('LearnMoreRewardProgram', {
45→        analytics: {
46→          screen_name: 'saiba_mais',
47→          screen_class: 'hub_recompensas_spmais',
48→          screen_bussines: 'monetizacao',
49→          screen_info: {
50→            location_1: 'monetizacao',
51→            location_2: 'hub_recompensas_spmais',
52→            location_3: 'saiba_mais',
53→          },
54→        },
55→      });
56→    },
57→    [
58→      data,
59→      navigation,
60→      parameterPointsProgramActions,
61→    ],
62→  );
63→
64→  return (
65→    <LearnMorePointsSectionView
66→      data={data}
67→      isLoading={status === ParameterPointsProgramStatus.LOADING}
68→      isError={status === ParameterPointsProgramStatus.ERROR}
69→      onPress={handlePress}
70→      width={width}
71→    />
72→  );
73→}
