  1→import { NavigationProp, useNavigation } from '@react-navigation/native';
  2→import { useCallback, useEffect, useMemo } from 'react';
  3→import { eventSelectContent } from '~/constants/functions';
  4→import { PropsRootStack } from '../../../routes/Models';
  5→import {
  6→  KEY_NAME_TO_ICON,
  7→  NAME_TO_ICON,
  8→  getNormalizedKeyName,
  9→} from '../../../screens/Points/data';
 10→import { PointsCardItem } from '../../../screens/Points/Models';
 11→import { usePermission } from '../../../services';
